import asyncio
from playwright.async_api import async_playwright
import json
import re
from datetime import datetime

async def fetch_all():
    all_data = []

    async with async_playwright() as p:
        browser = await p.chromium.launch(headless=True)
        context = await browser.new_context()
        page = await context.new_page()

        await page.goto('https://www.zhcw.com/kjxx/qlc/')
        await page.wait_for_load_state('networkidle')

        # 点击"近100期"
        span = await page.query_selector('span.annq[data-z="100"]')
        if span:
            await span.click()
            await page.wait_for_timeout(3000)

        # 使用evaluate执行请求
        result = await page.evaluate('''
            async () => {
                const data = [];
                const pageSize = 50;
                let page = 1;

                while (page <= 10) {
                    const url = `https://jc.zhcw.com/port/client_json.php?callback=callback&transactionType=10001001&lotteryId=3&issueCount=100&pageNum=${page}&pageSize=${pageSize}&tt=0.1`;

                    try {
                        const resp = await fetch(url);
                        const text = await resp.text();
                        const match = text.match(/callback\\((.*)\\)$/);
                        if (match) {
                            const jsonData = JSON.parse(match[1]);
                            if (jsonData.data && jsonData.data.length > 0) {
                                for (const item of jsonData.data) {
                                    data.push({
                                        period: item.issue,
                                        date: item.openTime,
                                        basic: item.frontWinningNum.split(' ').slice(0,7),
                                        special: item.backWinningNum
                                    });
                                }
                                console.log(`Page ${page}: got ${jsonData.data.length}, total ${jsonData.total}`);
                                if (jsonData.data.length < pageSize) break;
                                page++;
                            } else {
                                break;
                            }
                        } else {
                            break;
                        }
                    } catch (e) {
                        console.log('Error: ' + e.message);
                        break;
                    }
                }
                return data;
            }
        ''')

        print(f"获取到 {len(result)} 条数据")

        await browser.close()

        # 转换为标准格式
        for item in result:
            all_data.append({
                'period': item.get('period', ''),
                'date': item.get('date', ''),
                'basic_numbers': sorted([n.zfill(2) for n in item.get('basic', [])]),
                'special_number': item.get('special', '').zfill(2) if item.get('special') else ''
            })

    # 排序
    all_data.sort(key=lambda x: x.get('period', ''), reverse=True)

    print(f"\n共 {len(all_data)} 条数据")

    # 保存
    with open('/home/lang/.openclaw/workspace/caipiao/qlc_history.json', 'w') as f:
        json.dump(all_data, f, ensure_ascii=False, indent=2)

    with open('/home/lang/.openclaw/workspace/caipiao/qlc_history.txt', 'w') as f:
        f.write("七乐彩历史开奖数据\n")
        f.write(f"更新时间: {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}\n")
        f.write("=" * 60 + "\n\n")
        for item in all_data:
            basic = ' '.join(item.get('basic_numbers', []))
            special = item.get('special_number', '')
            f.write(f"{item['period']} {item['date']}  {basic} + {special}\n")

    print("\n前5条:")
    for item in all_data[:5]:
        print(f"  {item['period']} {item['date']} {' '.join(item['basic_numbers'])} + {item['special_number']}")

    print("\n✅ 完成!")

asyncio.run(fetch_all())
